using Dapper; using ValoraPesquisa.Application.Contracts; using ValoraPesquisa.Application.DTOs; using ValoraPesquisa.Domain.Entities; using ValoraPesquisa.Infrastructure.Database;
namespace ValoraPesquisa.Infrastructure.Repositories;
public sealed class PlanRepository(PostgresConnectionFactory db):IPlanRepository{const string C="id,code,name,description,monthly_price MonthlyPrice,annual_price AnnualPrice,status,display_order DisplayOrder,created_at CreatedAt,updated_at UpdatedAt,is_deleted IsDeleted"; public async Task<IReadOnlyList<PlanDto>> ListAsync(){using var c=db.Create();return (await c.QueryAsync<PlanDto>($"select {C} from valorapesquisa.plans where is_deleted=false order by display_order")).ToList();} public async Task<PlanDto?> GetByCodeAsync(string code){using var c=db.Create();return await c.QueryFirstOrDefaultAsync<PlanDto>($"select {C} from valorapesquisa.plans where code=@code and is_deleted=false",new{code});} public async Task<PlanDto?> GetByIdAsync(Guid id){using var c=db.Create();return await c.QueryFirstOrDefaultAsync<PlanDto>($"select {C} from valorapesquisa.plans where id=@id",new{id});} public async Task<PlanDto> CreateAsync(Plan p){using var c=db.Create();await c.ExecuteAsync("insert into valorapesquisa.plans(id,code,name,description,monthly_price,annual_price,status,display_order,created_at,updated_at,is_deleted) values(@Id,@Code,@Name,@Description,@MonthlyPrice,@AnnualPrice,@Status,@DisplayOrder,@CreatedAt,@UpdatedAt,@IsDeleted)",p);return (await GetByIdAsync(p.Id))!;} public async Task<PlanDto> UpdateAsync(Plan p){using var c=db.Create();await c.ExecuteAsync("update valorapesquisa.plans set code=@Code,name=@Name,description=@Description,monthly_price=@MonthlyPrice,annual_price=@AnnualPrice,status=@Status,display_order=@DisplayOrder,updated_at=now(),is_deleted=@IsDeleted where id=@Id",p);return (await GetByIdAsync(p.Id))!;} public async Task<PlanLimitDto?> GetLimitsAsync(string planCode){using var c=db.Create();return await c.QueryFirstOrDefaultAsync<PlanLimitDto>("select l.id,l.plan_id PlanId,l.active_surveys ActiveSurveys,l.responses_per_month ResponsesPerMonth,l.users,l.managers,l.forms,l.public_links PublicLinks,l.email_invites_per_month EmailInvitesPerMonth,l.storage_mb StorageMb,l.created_at CreatedAt,l.updated_at UpdatedAt from valorapesquisa.plan_limits l join valorapesquisa.plans p on p.id=l.plan_id where p.code=@planCode",new{planCode});} public async Task<IReadOnlyList<PlanCapabilityDto>> GetCapabilitiesAsync(string planCode){using var c=db.Create();return (await c.QueryAsync<PlanCapabilityDto>("select pc.id,pc.plan_id PlanId,pc.capability_code CapabilityCode,pc.enabled from valorapesquisa.plan_capabilities pc join valorapesquisa.plans p on p.id=pc.plan_id where p.code=@planCode",new{planCode})).ToList();}}
public sealed class ModuleRepository(PostgresConnectionFactory db):IModuleRepository{const string C="id,code,name,description,category,status,display_order DisplayOrder,minimum_plan_code MinimumPlanCode,created_at CreatedAt,updated_at UpdatedAt,is_deleted IsDeleted"; public async Task<IReadOnlyList<ModuleDto>> ListAsync(){using var c=db.Create();return (await c.QueryAsync<ModuleDto>($"select {C} from valorapesquisa.modules where is_deleted=false order by display_order")).ToList();} public async Task<ModuleDto?> GetByCodeAsync(string code){using var c=db.Create();return await c.QueryFirstOrDefaultAsync<ModuleDto>($"select {C} from valorapesquisa.modules where code=@code and is_deleted=false",new{code});} public async Task<IReadOnlyList<OrganizationModuleDto>> ListByOrganizationAsync(Guid organizationId){using var c=db.Create();return (await c.QueryAsync<OrganizationModuleDto>("select om.id,om.organization_id OrganizationId,om.module_id ModuleId,m.code ModuleCode,m.name ModuleName,om.enabled,om.source,om.created_at CreatedAt,om.updated_at UpdatedAt from valorapesquisa.organization_modules om join valorapesquisa.modules m on m.id=om.module_id where om.organization_id=@organizationId order by m.display_order",new{organizationId})).ToList();} public async Task<OrganizationModuleDto> SetOrganizationModuleAsync(Guid organizationId,string moduleCode,bool enabled,string source){using var c=db.Create();var module=await GetByCodeAsync(moduleCode)??throw new ArgumentException("Módulo não encontrado."); var id=Guid.NewGuid(); await c.ExecuteAsync("insert into valorapesquisa.organization_modules(id,organization_id,module_id,enabled,source,created_at) values(@id,@organizationId,@moduleId,@enabled,@source,now()) on conflict(organization_id,module_id) do update set enabled=excluded.enabled,source=excluded.source,updated_at=now()",new{id,organizationId,moduleId=module.Id,enabled,source}); return (await ListByOrganizationAsync(organizationId)).First(x=>x.ModuleCode==moduleCode);}}
public sealed class SubscriptionRepository(PostgresConnectionFactory db):ISubscriptionRepository{public async Task<SubscriptionDto?> GetCurrentAsync(Guid organizationId){using var c=db.Create();return await c.QueryFirstOrDefaultAsync<SubscriptionDto>("select s.id,s.organization_id OrganizationId,s.plan_id PlanId,p.code PlanCode,p.name PlanName,s.status,s.billing_status BillingStatus,s.starts_at StartsAt,s.expires_at ExpiresAt,s.trial_ends_at TrialEndsAt,s.cancelled_at CancelledAt,s.created_at CreatedAt,s.updated_at UpdatedAt from valorapesquisa.subscriptions s join valorapesquisa.plans p on p.id=s.plan_id where s.organization_id=@organizationId order by s.created_at desc limit 1",new{organizationId});} public async Task<SubscriptionDto> ChangePlanAsync(Guid organizationId,string planCode){using var c=db.Create();var plan=await c.QuerySingleAsync<PlanDto>("select id,code,name,description,monthly_price MonthlyPrice,annual_price AnnualPrice,status,display_order DisplayOrder,created_at CreatedAt,updated_at UpdatedAt,is_deleted IsDeleted from valorapesquisa.plans where code=@planCode",new{planCode}); var id=Guid.NewGuid(); await c.ExecuteAsync("insert into valorapesquisa.subscriptions(id,organization_id,plan_id,status,billing_status,starts_at,created_at) values(@id,@organizationId,@planId,'active','ok',now(),now())",new{id,organizationId,planId=plan.Id}); await c.ExecuteAsync("update valorapesquisa.organizations set plan_code=@planCode,updated_at=now() where id=@organizationId",new{planCode,organizationId}); return (await GetCurrentAsync(organizationId))!;} public async Task<SubscriptionDto> ChangeStatusAsync(Guid organizationId,string status,string billingStatus){using var c=db.Create();await c.ExecuteAsync("update valorapesquisa.subscriptions set status=@status,billing_status=@billingStatus,updated_at=now(),cancelled_at=case when @status='cancelled' then now() else cancelled_at end where id=(select id from valorapesquisa.subscriptions where organization_id=@organizationId order by created_at desc limit 1)",new{organizationId,status,billingStatus});return (await GetCurrentAsync(organizationId))!;} public Task<SubscriptionDto> CreateInitialAsync(Guid organizationId,string planCode)=>ChangePlanAsync(organizationId,planCode);}
public sealed class UsageRepository(PostgresConnectionFactory db):IUsageRepository{static DateTime M(DateTime? m=null){var d=m??DateTime.UtcNow;return new DateTime(d.Year,d.Month,1);} public async Task<UsageMonthlyDto> GetMonthlyAsync(Guid organizationId,DateTime? month=null){using var c=db.Create();var mo=M(month); var existing=await c.QueryFirstOrDefaultAsync<UsageMonthlyDto>("select id,organization_id OrganizationId,month,active_surveys_count ActiveSurveysCount,responses_count ResponsesCount,users_count UsersCount,managers_count ManagersCount,forms_count FormsCount,public_links_count PublicLinksCount,email_invites_count EmailInvitesCount,storage_mb_used StorageMbUsed,updated_at UpdatedAt from valorapesquisa.usage_monthly where organization_id=@organizationId and month=@mo",new{organizationId,mo}); return existing??await RecalculateAsync(organizationId,month);} public async Task<UsageMonthlyDto> RecalculateAsync(Guid organizationId,DateTime? month=null){using var c=db.Create();var mo=M(month);var counts=new{Active=await CountActiveSurveysAsync(organizationId),Responses=await c.ExecuteScalarAsync<int>("select count(*) from valorapesquisa.responses where organization_id=@organizationId and completed_at>=@mo and completed_at<@next",new{organizationId,mo,next=mo.AddMonths(1)}),Users=await CountUsersAsync(organizationId),Managers=await CountManagersAsync(organizationId),Forms=await CountFormsAsync(organizationId),Links=await CountPublicLinksAsync(organizationId)}; var id=Guid.NewGuid(); await c.ExecuteAsync("insert into valorapesquisa.usage_monthly(id,organization_id,month,active_surveys_count,responses_count,users_count,managers_count,forms_count,public_links_count,email_invites_count,storage_mb_used,updated_at) values(@id,@organizationId,@mo,@Active,@Responses,@Users,@Managers,@Forms,@Links,0,0,now()) on conflict(organization_id,month) do update set active_surveys_count=excluded.active_surveys_count,responses_count=excluded.responses_count,users_count=excluded.users_count,managers_count=excluded.managers_count,forms_count=excluded.forms_count,public_links_count=excluded.public_links_count,updated_at=now()",new{id,organizationId,mo,counts.Active,counts.Responses,counts.Users,counts.Managers,counts.Forms,counts.Links}); return await GetMonthlyAsync(organizationId,month);} public async Task IncrementResponsesAsync(Guid organizationId,DateTime? month=null){await RecalculateAsync(organizationId,month);} public async Task<int> CountActiveSurveysAsync(Guid o){using var c=db.Create();return await c.ExecuteScalarAsync<int>("select count(*) from valorapesquisa.surveys where organization_id=@o and status='published' and is_deleted=false",new{o});} public async Task<int> CountFormsAsync(Guid o){using var c=db.Create();return await c.ExecuteScalarAsync<int>("select count(*) from valorapesquisa.forms where organization_id=@o and is_deleted=false",new{o});} public async Task<int> CountUsersAsync(Guid o){using var c=db.Create();return await c.ExecuteScalarAsync<int>("select count(*) from valorapesquisa.users where organization_id=@o and is_deleted=false",new{o});} public async Task<int> CountManagersAsync(Guid o){using var c=db.Create();return await c.ExecuteScalarAsync<int>("select count(*) from valorapesquisa.users where organization_id=@o and role in ('empresa_admin','gestor_pesquisa','gestor_area') and is_deleted=false",new{o});} public async Task<int> CountPublicLinksAsync(Guid o){using var c=db.Create();return await c.ExecuteScalarAsync<int>("select count(*) from valorapesquisa.survey_links where organization_id=@o and status='active'",new{o});}}
